- Existing Unit Test Code: package org.jsoup;

import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.parser.Parser;
import org.jsoup.safety.Safelist;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;

import java.io.ByteArrayInputStream;
import java.io.File;
import java.io.IOException;
import java.io.InputStream;
import java.net.InetSocketAddress;
import java.net.URL;
import java.nio.file.Files;
import java.nio.file.Path;

import static org.junit.jupiter.api.Assertions.*;
public class Jsoup_parse_0_Test {

    @Test
    @DisplayName("TC01_O1: parse(String html, String baseUri) with valid HTML and non-empty baseUri returns parsed Document")
    public void test_TC01_O1() {
        String html = "<p>Test</p>";
        String baseUri = "http://example.com/";
        Document doc = Jsoup.parse(html, baseUri);
        assertAll(
            () -> assertTrue(doc.html().contains("<p>Test</p>"), "Should contain the paragraph HTML"),
            () -> assertEquals("http://example.com/", doc.baseUri(), "Base URI must be set correctly")
        );
    }

    @Test
    @DisplayName("TC02_O1: parse(String html, String baseUri) with null html throws IllegalArgumentException")
    public void test_TC02_O1() {
        String html = null;
        String baseUri = "http://x/";
        assertThrows(IllegalArgumentException.class, () -> Jsoup.parse(html, baseUri));
    }

    @Test
    @DisplayName("TC03_O2: parse(String html, String baseUri, Parser parser) with valid parser returns Document via parseInput")
    public void test_TC03_O2() {
        String html = "<div>OK</div>";
        String baseUri = "base";
        Parser p = Parser.xmlParser();
        Document doc = Jsoup.parse(html, baseUri, p);
        assertAll(
            () -> assertTrue(doc.html().contains("<div>OK</div>"), "Should include provided div"),
            () -> assertEquals("base", doc.baseUri(), "Should set baseUri from argument")
        );
    }

    @Test
    @DisplayName("TC04_O3: parse(String html, Parser parser) with empty html yields empty Document body")
    public void test_TC04_O3() {
        String html = "";
        Parser p = Parser.htmlParser();
        Document doc = Jsoup.parse(html, p);
        assertAll(
            () -> assertTrue(doc.body().html().isEmpty(), "Body should be empty for empty input"),
            () -> assertEquals("", doc.baseUri(), "Default baseUri is empty string")
        );
    }

    @Test
    @DisplayName("TC05_O4: parse(String html) with fragment HTML returns Document with body containing fragment")
    public void test_TC05_O4() {
        String html = "<span>F</span>";
        Document doc = Jsoup.parse(html);
        assertAll(
            () -> assertEquals("<span>F</span>", doc.body().html(), "Body must reflect the fragment"),
            () -> assertEquals("", doc.baseUri(), "Default baseUri is empty string")
        );
    }

    @Test
    @DisplayName("TC06_O5: parse(File file, String charsetName, String baseUri) with valid UTF-8 file returns Document")
    public void test_TC06_O5() throws IOException {
        Path temp = Files.createTempFile("test", ".html");
        Files.write(temp, "<h1>Hi</h1>".getBytes("UTF-8"));
        File f = temp.toFile();
        String cs = "UTF-8";
        String base = "http://b/";
        Document doc = Jsoup.parse(f, cs, base);
        assertAll(
            () -> assertTrue(doc.html().contains("<h1>Hi</h1>"), "HTML from file must be parsed"),
            () -> assertEquals("http://b/", doc.baseUri(), "BaseUri must match provided")
        );
        temp.toFile().delete();
    }

    @Test
    @DisplayName("TC07_O6: parse(File file, String charsetName) with null charsetName defaults to BOM/meta detection")
    public void test_TC07_O6() throws IOException {
        Path temp = Files.createTempFile("a", ".html");
        Files.write(temp, "<p>X</p>".getBytes());
        File f = temp.toFile();
        String cs = null;
        Document doc = Jsoup.parse(f, cs);
        assertAll(
            () -> assertTrue(doc.html().contains("<p>X</p>"), "Should parse HTML even without charset hint"),
            () -> assertEquals(f.getAbsolutePath(), doc.baseUri(), "BaseUri should default to file path")
        );
        temp.toFile().delete();
    }

    @Test
    @DisplayName("TC08_O7: parse(InputStream in, String charsetName, String baseUri) with ByteArrayInputStream and custom baseUri")
    public void test_TC08_O7() throws IOException {
        String s = "<b>1</b>";
        InputStream in = new ByteArrayInputStream(s.getBytes("UTF-8"));
        String cs = "UTF-8";
        String base = "http://u/";
        Document doc = Jsoup.parse(in, cs, base);
        assertAll(
            () -> assertEquals("<b>1</b>", doc.body().html(), "Body HTML must equal input"),
            () -> assertEquals("http://u/", doc.baseUri(), "BaseUri must match argument")
        );
    }

    @Test
    @DisplayName("TC09_O8: parse(URL url, int timeoutMillis) with valid http URL returns Document")
    public void test_TC09_O8() throws Exception {
        com.sun.net.httpserver.HttpServer server = com.sun.net.httpserver.HttpServer.create(new InetSocketAddress(0), 0);
        server.createContext("/test", exch -> {
            byte[] resp = "<i>OK</i>".getBytes("UTF-8");
            exch.sendResponseHeaders(200, resp.length);
            exch.getResponseBody().write(resp);
            exch.close();
        });
        server.start();
        int port = server.getAddress().getPort();
        URL url = new URL("http://localhost:" + port + "/test");
        Document doc = Jsoup.parse(url, 5000);
        server.stop(0);
        assertTrue(doc.html().contains("<i>OK</i>"), "Should fetch and parse <i>OK</i> from server");
    }

    @Test
    @DisplayName("TC10_O1: parse+clean relative-link with preserveRelativeLinks true returns link preserved")
    public void test_TC10_O1() {
        String html = "<a href='/x'>X</a>";
        String base = "";
        Safelist s = Safelist.relaxed().preserveRelativeLinks(true);
        String out = Jsoup.clean(html, base, s);
        assertEquals("<a href=\"/x\">X</a>", out, "Relative link should be preserved by safelist");
    }
}
- Error Log Message: 

2) **What to Produce**
- Output a single JSON object containing an array named `"ErrorGuides"`.
- Each element of `"ErrorGuides"` MUST have exactly these keys:
  - `"ErrorSpot"`: A precise pointer to the error location (e.g., method name, file path + line number, or `"import section"`). If it is an import error, specify `"import section"` and the file.
  - `"ErrorCause"`: A concise English description of the root cause (why it failed).
  - `"ErrorGuide"`: A pseudocode-style, step-by-step fix guide in English.
  - `"Before"`: The minimal code fragment (or signature) that is wrong.
  - `"After"`: The corrected minimal code fragment (or signature) that should replace the `"Before"`.
- Only report issues that are evidenced by the provided error log. Do not invent additional problems.
- If multiple errors exist, list them in the order they appear in the log.

3) **Constraints**
- Do NOT change the number of test scenarios (this prompt does not ask you to output fixed tests).
- Keep fixes minimal and focused strictly on the error causes shown in the log.
- If the error references a missing/invalid constructor or generic type inference failure, show the corrected constructor/generics explicitly in `"After"`.
- If the error references class/file name mismatch, `"ErrorSpot"` must include both the public class name and the filename, and `"Before"`/`"After"` must reflect the correct pairing.
- If reflection access or import is the issue, set fields accessible and ensure imports are correct, but only if such errors are indicated in the log.
- Avoid mocks/abstractions unless the log directly points to them.

4) **Style**
- All explanations (`"ErrorCause"` and `"ErrorGuide"`) should be in **English**.
- Keep `"Before"`/`"After"` as short, minimal code blocks or single-line signatures where possible.
- If line numbers are present in the log, include them in `"ErrorSpot"` (e.g., `"…Test.java:123:45"`).

[Error Categories to Handle]
You must analyze and report all errors from the following categories:
  1) Type: Syntax / Compile Error
  Description: Missing import, invalid class, wrong method signature, incompatible types
  Examples: “cannot find symbol”, “missing return statement”, “incompatible types”

  2) Type: Runtime Error
  Description: Exception occurring during test execution
  Examples: “NullPointerException”, “IndexOutOfBoundsException”, “IllegalArgumentException”


[Rules for Each Error Type]
  1) Compile-Time Errors:
  Identify incorrect syntax, type, import, or constructor.
  Include file and class name if mismatched.
  Keep “Before” and “After” minimal and focused.

  2) Runtime Errors:
  Specify which statement threw the exception.
  Suggest fixes such as null checks, bounds checks, or proper initialization.


[Emphasis/Request]
- Minimize changes; focus on compilability/run-ability per the error log.
- Never summarize or remove scenarios; this prompt is ONLY for producing Error Guides.
- Ensure steps are practical and do not introduce infinite loops or unrelated edits.

[Output Format]
Return ONLY one JSON object, enclosed in triple backticks as `"json"`. The schema MUST be:

```json
{
  "ErrorGuides": [
    {
      "ErrorSpot": "<file path or class#method or 'import section'>",
      "ErrorCause": "<short and clear explanation of the cause>",
      "ErrorGuide": "<pseudocode-style step-by-step fix guide>",
      "Before": "<minimal code snippet that is wrong>",
      "After": "<corrected minimal code snippet>"
    }
    // ... more errors in log order
  ]
}

[SUMMARY]
Output strictly JSON (no extra text or markdown).
Focus only on real, logged issues.
Ensure minimal, safe, and realistic fixes.
Avoid any fix that could introduce infinite loops or unbounded execution.
Goal: Produce a clean, precise, developer-ready Error Guide JSON.
